public void initFromPurchAgreementHeader(PurchAgreementHeader _purchHeader)
{

    ETG_PurchaseAgreementHeader      eTG_PurchaseAgreementHeader;
    PurchAgreementHeader             purchAgreementHeader;

    next initFromPurchAgreementHeader( _purchHeader);


    select firstonly * from eTG_PurchaseAgreementHeader 
        where eTG_PurchaseAgreementHeader.PurchAgreementId == _purchHeader.PurchNumberSequence;

    this.PortOfDischarge               = eTG_PurchaseAgreementHeader.PortOfDischarge;
    this.DeliveryDescription           = eTG_PurchaseAgreementHeader.DeliveryDescription;
    this.TermPaymDescription           = eTG_PurchaseAgreementHeader.TermPaymDescription;
    this.Future                        = eTG_PurchaseAgreementHeader.Future;
    this.Consignee                     = eTG_PurchaseAgreementHeader.Consignee;
    this.OnAccountOf                   = eTG_PurchaseAgreementHeader.OnAccountOf;
    this.Notes                         = eTG_PurchaseAgreementHeader.Notes;
    this.Through                       = eTG_PurchaseAgreementHeader.Through;
    this.Notifytodifferentparty        = eTG_PurchaseAgreementHeader.Notifytodifferentparty;
    this.BuyerBank                     = eTG_PurchaseAgreementHeader.BuyerBank;
    this.SellerBank                    = eTG_PurchaseAgreementHeader.SellerBank;
    this.SellerAccountNum              = eTG_PurchaseAgreementHeader.SellerAccountNum;
    this.PricingMonth                  = eTG_PurchaseAgreementHeader.PricingMonth;
    this.PricingFromDate               = eTG_PurchaseAgreementHeader.PricingFromDate;
    this.PricingTodate                 = eTG_PurchaseAgreementHeader.PricingTodate;
    this.AdvanceDue                    = eTG_PurchaseAgreementHeader.AdvanceDue;
    this.FromDatePort                  = eTG_PurchaseAgreementHeader.FromDatePort;
    this.ToDatePort                    = eTG_PurchaseAgreementHeader.ToDatePort;
    this.PortOfLoading                 = eTG_PurchaseAgreementHeader.PortOfLoading;
    this.PortOfDischarge               = eTG_PurchaseAgreementHeader.PortOfDischarge;
    this.CustomImport                  = eTG_PurchaseAgreementHeader.CustomImport;
    this.ImportDate                    = eTG_PurchaseAgreementHeader.ImportDate;
    this.Number                        = eTG_PurchaseAgreementHeader.Number;
    this.CommissionType                = eTG_PurchaseAgreementHeader.CommissionType;
    this.TypeValue                     = eTG_PurchaseAgreementHeader.TypeValue;
    this.DisplayTotalCalculatedCommission = eTG_PurchaseAgreementHeader.DisplayTotalCalculatedCommission;
    this.TermsOfDelDescription         = eTG_PurchaseAgreementHeader.TermsOfDelDescription;
    this.PurchAgreementId              = eTG_PurchaseAgreementHeader.PurchAgreementId;
    this.PurchPoolId                   = eTG_PurchaseAgreementHeader.PurchPoolId;
    this.BuyerAccountNum               = eTG_PurchaseAgreementHeader.BuyerAccountNum;
    this.BuyerDeliveryAddress          = eTG_PurchaseAgreementHeader.BuyerDeliveryAddress;
    this.SellerDeliveryAddress         = eTG_PurchaseAgreementHeader.SellerDeliveryAddress;
    this.BuyerSecondaryBank            = eTG_PurchaseAgreementHeader.BuyerSecondaryBank;
    this.SellerSecondaryBank           = eTG_PurchaseAgreementHeader.SellerSecondaryBank;
    this.Name                          = eTG_PurchaseAgreementHeader.Name;
    this.Address                       = eTG_PurchaseAgreementHeader.Address;
    this.PortOfLoadingDesc             = eTG_PurchaseAgreementHeader.PortOfLoadingDesc;
    this.PortOfDischargeDesc           = eTG_PurchaseAgreementHeader.PortOfDischargeDesc;
    this.ShipperBuyer                  = eTG_PurchaseAgreementHeader.ShipperBuyer;
    this.BuyerName                     = eTG_PurchaseAgreementHeader.buyerName();
    this.SellerName                    = eTG_PurchaseAgreementHeader.sellerName();
    this.BrokerName                    = eTG_PurchaseAgreementHeader.brokerName();


}
